INSERT INTO ess_flashcard_topics (id, label, color, unit, sort_order) VALUES ('ess_t3', 'Biodiversity & Conservation', '#7AAD6B', '3', 3);
INSERT INTO ess_flashcard_topics (id, label, color, unit, sort_order) VALUES ('ess_t4', 'Water & Aquatic Systems', '#7AAD6B', '4', 4);
INSERT INTO ess_flashcard_topics (id, label, color, unit, sort_order) VALUES ('ess_t5', 'Soil & Food Production', '#7AAD6B', '5', 5);
INSERT INTO ess_flashcard_topics (id, label, color, unit, sort_order) VALUES ('ess_t6', 'Atmospheric Systems', '#7AAD6B', '6', 6);
INSERT INTO ess_flashcard_topics (id, label, color, unit, sort_order) VALUES ('ess_t7', 'Climate Change & Energy', '#7AAD6B', '7', 7);
INSERT INTO ess_flashcard_topics (id, label, color, unit, sort_order) VALUES ('ess_t8', 'Human Systems & Resources', '#7AAD6B', '8', 8);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'Biodiversity', 'The variety of life at all levels of biological organisation—genetic, species and ecosystem diversity.', 1);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'Genetic diversity', 'The range of genetic variation found within a species or population.', 2);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'Species diversity', 'The variety of species present in an area, including both richness (number of species) and evenness (relative abundance).', 3);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'Ecosystem diversity', 'The variety of different ecosystems or habitats within a region.', 4);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'Endemic species', 'A species that is found naturally in only one specific geographic area.', 5);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'HIPPCO', 'Acronym for six main drivers of biodiversity loss: Habitat loss, Invasive species, Pollution, Population growth, Climate change, Overexploitation.', 6);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'Simpson''s Reciprocal Index (D)', 'A quantitative measure of biodiversity: D = N(N-1) / Σn(n-1). Higher D = greater diversity.', 7);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'IUCN Red List', 'A comprehensive inventory classifying species based on their extinction risk (Least Concern to Extinct).', 8);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'CITES', 'Convention on International Trade in Endangered Species: an international agreement regulating cross-border trade in wildlife to prevent over-exploitation.', 9);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'In-situ conservation', 'Conservation of species within their natural habitat (e.g. national parks, marine protected areas, wildlife corridors).', 10);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'Ex-situ conservation', 'Conservation of species outside their natural habitat (e.g. zoos, botanical gardens, seed banks, captive breeding).', 11);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'Natural selection', 'The process by which organisms with favourable traits for a given environment are more likely to survive, reproduce and pass on those traits.', 12);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'Evolution', 'The cumulative change in the heritable characteristics of a population over successive generations.', 13);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'Speciation', 'The formation of new and distinct species through evolutionary processes, often driven by geographic or reproductive isolation.', 14);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'Mass extinction', 'A widespread and rapid decrease in biodiversity in which a large proportion of species goes extinct in a geologically short period.', 15);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'Island biogeography', 'Theory explaining species richness on islands based on island size and distance from the mainland; larger and closer islands have more species.', 16);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'Biodiversity hotspot', 'A region with exceptionally high concentrations of endemic species that has lost at least 70% of its original habitat.', 17);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'Habitat fragmentation', 'The breaking up of large continuous habitats into smaller, isolated patches, reducing biodiversity through edge effects and limited dispersal.', 18);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'Edge effect', 'Changes in population or community structure at the boundary of two habitats; fragmented habitats have proportionally more edge.', 19);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'Wildlife corridor', 'A strip of habitat connecting isolated patches, enabling species movement and gene flow between populations.', 20);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t3', 'Convention on Biological Diversity (CBD)', 'An international treaty (1992) with three main goals: conservation of biodiversity, sustainable use of its components, and equitable sharing of benefits from genetic resources.', 21);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t4', 'Hydrological cycle', 'The continuous movement of water between the atmosphere, land surface and underground through evaporation, condensation, precipitation, infiltration and runoff.', 1);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t4', 'Aquifer', 'An underground layer of water-bearing permeable rock or sediment from which groundwater can be extracted.', 2);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t4', 'Water table', 'The upper surface of the zone of saturation in the ground, below which all pore spaces are filled with water.', 3);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t4', 'Eutrophication', 'Enrichment of a water body with nutrients (mainly nitrogen and phosphorus), leading to excessive algal growth, oxygen depletion and biodiversity loss.', 4);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t4', 'Dead zone', 'An area of water with very low dissolved oxygen (hypoxia), often caused by eutrophication, where most aquatic life cannot survive.', 5);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t4', 'Point-source pollution', 'Pollution entering a water body from a single identifiable source (e.g. a factory outfall pipe).', 6);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t4', 'Non-point-source pollution', 'Pollution entering a water body from diffuse or widespread sources (e.g. agricultural runoff, urban stormwater).', 7);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t4', 'Biological oxygen demand (BOD)', 'A measure of the amount of dissolved oxygen consumed by microorganisms in decomposing organic matter in water. High BOD = more pollution.', 8);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t4', 'Maximum sustainable yield (MSY)', 'The maximum amount of a resource (e.g. fish) that can be harvested indefinitely without causing the stock to decline.', 9);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t4', 'Aquaculture', 'The farming of aquatic organisms such as fish, shellfish or seaweed in controlled conditions.', 10);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t4', 'Overfishing', 'Harvesting fish at a rate faster than the population can replenish, leading to stock collapse.', 11);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t4', 'Bycatch', 'Non-target species caught unintentionally during commercial fishing operations.', 12);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t4', 'Ocean acidification', 'The decrease in pH of ocean water caused by absorption of excess atmospheric CO2, threatening shell-forming organisms.', 13);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t4', 'Desalination', 'The process of removing salt from seawater to produce freshwater, energy-intensive but vital in arid regions.', 14);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t4', 'Grey water', 'Wastewater from sinks, showers and washing machines that can be recycled for non-potable uses.', 15);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t4', 'Water footprint', 'The total volume of freshwater used to produce goods and services consumed by an individual, community or nation.', 16);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t4', 'Wetland', 'An area of land where the soil is saturated with water permanently or seasonally; provides filtration, flood control and habitat.', 17);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t5', 'Soil', 'A complex mixture of minerals, organic matter, water, air and living organisms that forms on the Earth''s surface.', 1);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t5', 'Soil profile', 'A vertical cross-section through soil showing distinct horizontal layers (horizons): O, A, B, C and bedrock.', 2);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t5', 'O horizon', 'The uppermost soil layer, consisting primarily of decomposing organic matter (humus and leaf litter).', 3);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t5', 'A horizon (topsoil)', 'The layer below the O horizon; dark, rich in humus, and where most biological activity and root growth occurs.', 4);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t5', 'B horizon (subsoil)', 'The zone of accumulation below the A horizon where minerals leached from above are deposited.', 5);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t5', 'Soil erosion', 'The removal of the top layer of soil by wind, water or human activity, faster than it can be replaced.', 6);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t5', 'Soil degradation', 'The decline in soil quality due to misuse, leading to loss of fertility, structure or function.', 7);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t5', 'Humus', 'Dark, stable, decomposed organic matter in soil that improves structure, water retention and nutrient availability.', 8);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t5', 'Green Revolution', 'A period (1950s-1970s) of increased agricultural production from high-yield crop varieties, irrigation, chemical fertilisers and pesticides.', 9);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t5', 'Monoculture', 'The agricultural practice of growing a single crop species over a large area, increasing vulnerability to pests and soil depletion.', 10);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t5', 'Polyculture', 'Growing multiple crop species together in the same area, promoting biodiversity and soil health.', 11);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t5', 'Bioaccumulation', 'The gradual accumulation of a substance (e.g. a pesticide or heavy metal) in the tissues of a living organism over time.', 12);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t5', 'Biomagnification', 'The increasing concentration of a persistent substance in organisms at successively higher trophic levels of a food chain.', 13);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t5', 'Organic farming', 'Agriculture without synthetic chemicals or GMOs, relying on crop rotation, compost, biological pest control and natural fertilisers.', 14);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t5', 'Food miles', 'The distance food travels from producer to consumer; used as an indicator of environmental impact related to transport emissions.', 15);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t5', 'Salinisation', 'Accumulation of salts in soil, often caused by irrigation in arid areas, reducing soil fertility.', 16);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t5', 'Desertification', 'Land degradation in arid, semi-arid and dry sub-humid areas caused by climate variation and human activities.', 17);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t5', 'Carrying capacity (food)', 'The maximum population size that the environment can sustainably support with available food resources.', 18);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t5', 'Integrated pest management (IPM)', 'A sustainable pest control strategy combining biological, cultural, mechanical and minimal chemical methods.', 19);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t6', 'Atmosphere', 'The layer of gases surrounding the Earth, held in place by gravity, comprising ~78% nitrogen and ~21% oxygen.', 1);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t6', 'Troposphere', 'The lowest layer of the atmosphere (0-12 km) where weather occurs and where most air pollution concentrates.', 2);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t6', 'Stratosphere', 'The atmospheric layer above the troposphere (12-50 km) containing the ozone layer that absorbs UV radiation.', 3);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t6', 'Ozone layer', 'A region of the stratosphere with high concentration of ozone (O3) that absorbs harmful ultraviolet radiation.', 4);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t6', 'Ozone depletion', 'The thinning of the stratospheric ozone layer caused primarily by CFCs releasing chlorine atoms that catalytically destroy ozone molecules.', 5);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t6', 'CFCs (Chlorofluorocarbons)', 'Synthetic chemicals formerly used as refrigerants and propellants; break down in the stratosphere and release chlorine that destroys ozone.', 6);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t6', 'Montreal Protocol', 'An international treaty (1987) phasing out the production of ozone-depleting substances; widely considered the most successful environmental agreement.', 7);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t6', 'Primary pollutant', 'A pollutant emitted directly from a source into the atmosphere (e.g. CO, SO2, NOx, particulates).', 8);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t6', 'Secondary pollutant', 'A pollutant formed in the atmosphere by chemical reactions involving primary pollutants (e.g. tropospheric ozone, photochemical smog).', 9);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t6', 'Photochemical smog', 'A type of air pollution formed when sunlight triggers reactions between NOx and VOCs, producing ground-level ozone and other oxidants.', 10);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t6', 'Acid deposition', 'The settling of acidic particles and gases (wet: acid rain/snow; dry: particulates) from the atmosphere onto the Earth''s surface, caused mainly by SO2 and NOx emissions.', 11);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t6', 'Particulate matter (PM)', 'Tiny solid or liquid particles suspended in air; PM2.5 (<2.5um) and PM10 (<10um) are key health-damaging pollutants.', 12);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t6', 'Thermal inversion', 'A weather condition where a warm air layer traps cooler air below, preventing pollutants from dispersing vertically.', 13);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t6', 'Nitrogen oxides (NOx)', 'Gases produced by high-temperature combustion (vehicles, power plants) that contribute to smog and acid rain.', 14);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t6', 'Sulfur dioxide (SO2)', 'A gas released by burning fossil fuels (especially coal) and volcanic activity; major contributor to acid deposition.', 15);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t6', 'VOCs (Volatile Organic Compounds)', 'Carbon-containing chemicals that easily evaporate and react with NOx in sunlight to form photochemical smog.', 16);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t6', 'Indoor air pollution', 'Contamination of indoor air, often from burning biomass, cooking fuels, tobacco smoke or poor ventilation; a major health issue in developing countries.', 17);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t7', 'Greenhouse effect', 'Natural process where certain gases in the atmosphere absorb and re-radiate infrared radiation, warming the Earth''s surface.', 1);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t7', 'Enhanced greenhouse effect', 'The intensification of the natural greenhouse effect due to increased concentrations of greenhouse gases from human activities.', 2);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t7', 'Greenhouse gases', 'Gases that absorb and emit infrared radiation: CO2, CH4, N2O, water vapour, CFCs, and tropospheric ozone.', 3);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t7', 'Global warming', 'The long-term increase in Earth''s average surface temperature, primarily due to increased greenhouse gas concentrations.', 4);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t7', 'Climate change', 'Long-term shifts in temperature patterns and weather, driven by both natural factors and human activities.', 5);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t7', 'Carbon footprint', 'The total amount of greenhouse gases emitted directly and indirectly by an individual, organisation, event or product.', 6);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t7', 'Mitigation', 'Actions taken to reduce or prevent greenhouse gas emissions and slow climate change (e.g. renewable energy, reforestation).', 7);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t7', 'Adaptation', 'Adjustments made to reduce vulnerability to the effects of climate change (e.g. sea walls, drought-resistant crops).', 8);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t7', 'Paris Agreement (2015)', 'An international climate accord aiming to limit global warming to well below 2C, preferably 1.5C, above pre-industrial levels.', 9);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t7', 'Fossil fuels', 'Non-renewable energy sources (coal, oil, natural gas) formed from ancient organic matter; major source of CO2 emissions.', 10);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t7', 'Renewable energy', 'Energy from sources that are naturally replenished: solar, wind, hydroelectric, geothermal, tidal, biomass.', 11);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t7', 'Non-renewable energy', 'Energy from finite sources that cannot be replenished on a human timescale: fossil fuels and nuclear.', 12);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t7', 'Nuclear energy', 'Energy released from nuclear fission of heavy atoms (uranium, plutonium); low CO2 but produces radioactive waste.', 13);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t7', 'Solar energy', 'Energy harnessed from sunlight using photovoltaic cells or solar thermal systems.', 14);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t7', 'Wind energy', 'Kinetic energy from wind converted to electricity by turbines; intermittent but increasingly cost-effective.', 15);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t7', 'Hydroelectric power', 'Electricity generated by water flowing through turbines in dams; reliable but can disrupt river ecosystems.', 16);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t7', 'Ice-albedo feedback', 'A positive feedback: warming melts ice, exposes darker surface, absorbs more heat, further warming and melting.', 17);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t7', 'Carbon capture and storage (CCS)', 'Technology that captures CO2 from industrial sources and stores it underground to prevent atmospheric release.', 18);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t7', 'Energy security', 'The uninterrupted availability of energy sources at an affordable price for a nation or region.', 19);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t7', 'IPCC', 'Intergovernmental Panel on Climate Change: a UN body that assesses the science of climate change and publishes assessment reports.', 20);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t8', 'Ecological footprint', 'The area of biologically productive land and water required to produce the resources consumed and absorb the waste generated by an individual or population.', 1);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t8', 'Carrying capacity (human)', 'The maximum number of people that the Earth (or a region) can sustainably support given available resources and technology.', 2);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t8', 'Demographic transition model (DTM)', 'A model describing population change over time in 4-5 stages: from high birth/death rates to low birth/death rates as a country develops.', 3);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t8', 'Renewable resource', 'A natural resource that can be replenished at a rate equal to or faster than it is consumed (e.g. solar energy, timber, freshwater).', 4);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t8', 'Non-renewable resource', 'A natural resource that exists in finite quantities and is consumed faster than it can be replaced (e.g. fossil fuels, minerals).', 5);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t8', 'Replenishable resource', 'A resource that is non-living but is replenished by natural processes (e.g. groundwater, soil).', 6);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t8', 'Solid domestic waste', 'Waste generated by households, including food waste, packaging, paper, plastics and electronics.', 7);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t8', 'Waste hierarchy', 'Prioritised framework: Reduce, Reuse, Recycle, Recover (energy), Dispose (landfill). Prevention is most preferred.', 8);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t8', 'Circular economy', 'An economic model that minimises waste and resource extraction by keeping materials in use through repair, reuse, remanufacturing and recycling.', 9);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t8', 'Linear economy', 'A take-make-dispose model where resources are extracted, used once, and discarded as waste.', 10);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t8', 'Landfill', 'A site for disposal of waste by burial; can cause leachate pollution, methane emissions and land-use conflicts.', 11);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t8', 'Incineration', 'Burning waste at high temperatures to reduce volume; can generate energy but may release toxins if uncontrolled.', 12);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t8', 'E-waste', 'Discarded electronic devices; contains hazardous materials (lead, mercury) but also valuable recoverable metals.', 13);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t8', 'Pollution management', 'Strategies to address pollution: prevention (avoiding generation), regulation (setting limits) and clean-up (remediation after release).', 14);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t8', 'Biocapacity', 'The capacity of an area to regenerate the resources consumed and absorb the waste produced by a population.', 15);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t8', 'Earth Overshoot Day', 'The date each year when humanity''s resource consumption exceeds Earth''s biocapacity to regenerate those resources for that year.', 16);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t8', 'Sustainable development', 'Development that meets the needs of the present without compromising the ability of future generations to meet their own needs.', 17);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t8', 'EIA (Environmental Impact Assessment)', 'A process of evaluating the likely environmental impacts of a proposed project or development before it proceeds.', 18);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t8', 'Precautionary principle', 'The principle that if an action risks causing harm to the public or environment, precautionary measures should be taken even without full scientific certainty.', 19);
INSERT INTO ess_flashcards (topic_id, term, definition, sort_order) VALUES ('ess_t8', 'Tragedy of the commons', 'The depletion of a shared resource by individuals acting in their own self-interest, contrary to the common good (Hardin, 1968).', 20);
INSERT INTO ess_written_questions (id, category, difficulty, question_type, unit, marks, question_text, sort_order) VALUES ('ess_wq_1_01', 'Define / State', 'SL', 'short_answer', '1', 1, 'Define the term ''system'' as used in environmental science.', 1);
INSERT INTO ess_written_questions (id, category, difficulty, question_type, unit, marks, question_text, sort_order) VALUES ('ess_wq_1_02', 'Define / State', 'SL', 'short_answer', '1', 1, 'Define ''sustainability'' in the context of environmental management.', 2);
INSERT INTO ess_written_questions (id, category, difficulty, question_type, unit, marks, question_text, sort_order) VALUES ('ess_wq_1_03', 'Define / State', 'SL', 'short_answer', '1', 1, 'State one example of a positive feedback loop in a natural system.', 3);
INSERT INTO ess_written_questions (id, category, difficulty, question_type, unit, marks, question_text, sort_order) VALUES ('ess_wq_1_04', 'Define / State', 'SL', 'short_answer', '1', 1, 'State the difference between a closed system and an open system.', 4);
INSERT INTO ess_written_questions (id, category, difficulty, question_type, unit, marks, question_text, sort_order) VALUES ('ess_wq_1_05', 'Define / State', 'SL', 'short_answer', '1', 2, 'Define the terms ''inputs'' and ''outputs'' with reference to systems thinking.', 5);
INSERT INTO ess_written_questions (id, category, difficulty, question_type, unit, marks, question_text, sort_order) VALUES ('ess_wq_1_06', 'Define / State', 'SL', 'short_answer', '1', 1, 'State what is meant by ''equilibrium'' in a system.', 6);
INSERT INTO ess_written_questions (id, category, difficulty, question_type, unit, marks, question_text, sort_order) VALUES ('ess_wq_1_07', 'Outline / Describe', 'SL', 'short_answer', '1', 3, 'Outline how negative feedback maintains stability in an ecosystem.', 7);
INSERT INTO ess_written_questions (id, category, difficulty, question_type, unit, marks, question_text, sort_order) VALUES ('ess_wq_1_08', 'Outline / Describe', 'SL', 'short_answer', '1', 3, 'Describe the differences between ecocentrism, anthropocentrism and technocentrism as environmental value systems.', 8);
INSERT INTO ess_written_questions (id, category, difficulty, question_type, unit, marks, question_text, sort_order) VALUES ('ess_wq_1_09', 'Outline / Describe', 'SL', 'short_answer', '1', 4, 'Describe the role of models in environmental science, including their strengths and limitations.', 9);
INSERT INTO ess_written_questions (id, category, difficulty, question_type, unit, marks, question_text, sort_order) VALUES ('ess_wq_1_10', 'Outline / Describe', 'SL', 'short_answer', '1', 3, 'Outline the concept of a systems diagram, including storages, flows, and transfers.', 10);
INSERT INTO ess_written_questions (id, category, difficulty, question_type, unit, marks, question_text, sort_order) VALUES ('ess_wq_1_11', 'Outline / Describe', 'SL', 'short_answer', '1', 3, 'Outline how the concept of ''steady-state equilibrium'' applies to environmental systems.', 11);
INSERT INTO ess_written_questions (id, category, difficulty, question_type, unit, marks, question_text, sort_order) VALUES ('ess_wq_1_12', 'Outline / Describe', 'SL', 'short_answer', '1', 3, 'Describe one historical event that significantly changed perspectives on environmental value systems.', 12);
INSERT INTO ess_written_questions (id, category, difficulty, question_type, unit, marks, question_text, sort_order) VALUES ('ess_wq_1_13', 'Explain / Discuss', 'SL', 'short_answer', '1', 5, 'Explain how positive and negative feedback loops operate in the context of climate change.', 13);
